ee:message.ee:set-payload:
                    %dw 2.0
output application/json
var ar = vars.analysisRequest default {}
---
{
  sourceType: "orchestrated",
  requestedBy: (ar.requestedBy default "unknown") as String,
  priority: lower(trim((ar.priority default "normal") as String))
}
++
(if ((ar.logObjectUri default null) != null and !isEmpty(trim(ar.logObjectUri as String)))
  { logObjectUri: ar.logObjectUri as String }
else {})
